export type Cell = [number, number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const survives = (count: number, isAlive: boolean): boolean =>
  count === 3 || (count === 2 && isAlive);

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const cell: Cell = [x + dx, y + dy];
        const key = cellKey(cell);
        const entry = neighborCounts.get(key) ?? { cell, count: 0 };
        entry.count++;
        neighborCounts.set(key, entry);
      }
    }
  }

  const result: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
    if (survives(count, liveSet.has(key))) {
      result.push(cell);
    }
  }
  return result;
}
